    def test_joinPageDataEntry(self):
        self.driver.get("http://127.0.0.1:5500/teton/1.6/index.html")
        self.driver.set_window_size(779, 816)
        self.driver.find_element(By.LINK_TEXT, "Join Us").click()
        elements = self.driver.find_elements(By.CSS_SELECTOR, ".myinput:nth-child(2)")
        assert len(elements) > 0

        self.driver.find_element(By.NAME, "fname").send_keys("Gabriela")
        self.driver.find_element(By.NAME, "lname").send_keys("Rivera")
        self.driver.find_element(By.NAME, "bizname").send_keys("Cse")
        self.driver.find_element(By.NAME, "biztitle").send_keys("Software Dev")
        self.driver.find_element(By.NAME, "submit").click()

        elements = self.driver.find_elements(By.NAME, "email")
        assert len(elements) > 0

    def test_navigatetothehomepage(self):
        self.driver.get("http://127.0.0.1:5500/teton/1.6/index.html")
        self.driver.set_window_size(782, 816)
        assert len(self.driver.find_elements(By.CSS_SELECTOR, ".spotlight1 > .centered-image")) > 0
        assert len(self.driver.find_elements(By.CSS_SELECTOR, ".spotlight2")) > 0
        assert len(self.driver.find_elements(By.LINK_TEXT, "Join Us!")) > 0
        self.driver.find_element(By.LINK_TEXT, "Join Us!").click()
        assert self.driver.title == "Teton Idaho CoC"
